extends Enemy

# Weak skeleton: fatigue-less chip enemy. Nemá fatigue (žádný exhausted, žádný
# regen když zasáhne playera), zato player hity v jeho idle "chipují" skrz
# block za redukovaný damage (chip_multiplier). Low HP, dlouhé čitelné
# telegraphy, generous recovery, skoro jen weak útoky, žádné feinty.
# Per-type tunables žijí v `balance.json` sekci `enemy_weak`, čtené přes
# `Balance.enemy_weak` Dictionary (záměrně neflattenované — kolize s
# enemy_basic flat vars).

const BODY_SHEET := preload("res://sprites/skeleton-basic.png")     # placeholder copy of enemy_basic.png — real skeleton art TODO
const WEAPON_SHEET_WEAK := preload("res://sprites/enemy_basic_weapon.png")  # reuse — skeleton weapon art TODO
const BASE_TINT := Color(0.92, 0.95, 0.82, 1.0)   # bony pale tint to tell it apart from basic until real art


func _sprite_sheet() -> Texture2D:
	return BODY_SHEET


func _weapon_sheet() -> Texture2D:
	return WEAPON_SHEET_WEAK


func _base_tint() -> Color:
	return BASE_TINT


func has_fatigue() -> bool:
	return false


func idle_chip_multiplier() -> float:
	return float(Balance.enemy_weak.get("chip_multiplier", 0.34))


func max_hp() -> int:
	return int(Balance.enemy_weak.get("hp_max", 70))


func _pick_attack(rng_: RandomNumberGenerator) -> StringName:
	return &"strong" if rng_.randf() < float(Balance.enemy_weak.get("strong_probability", 0.05)) else &"weak"


func _pick_idle_duration(rng_: RandomNumberGenerator) -> int:
	return rng_.randi_range(int(Balance.enemy_weak.get("idle_min_ticks", 24)), int(Balance.enemy_weak.get("idle_max_ticks", 56)))


# speed_scale deliberately ignored — fixed readable timings (weak never scales).

func _threat_weak_ticks() -> int:
	return int(Balance.enemy_weak.get("threat_weak_ticks", 14))


func _threat_strong_ticks() -> int:
	return int(Balance.enemy_weak.get("threat_strong_ticks", 18))


func _recovery_weak_ticks() -> int:
	return int(Balance.enemy_weak.get("recovery_weak_ticks", 14))


func _recovery_strong_ticks() -> int:
	return int(Balance.enemy_weak.get("recovery_strong_ticks", 22))


func _stagger_ticks() -> int:
	return int(Balance.enemy_weak.get("stagger_ticks", 18))


func _exhausted_ticks() -> int:
	return int(Balance.enemy_weak.get("exhausted_ticks", 48))  # unreachable (no fatigue) but sane


func _feint_probability() -> float:
	return 0.0

extends Enemy

# First concrete enemy: 80 % weak, 20 % strong. Idle 32–64 ticks.
# Per-type tunables (threat/recovery/idle/probability) live in `balance.json`
# under the `enemy_basic` section, accessed via the `Balance` autoload.


func _pick_attack(rng_: RandomNumberGenerator) -> StringName:
	# Endless mode may add a small (capped) strong-probability bonus.
	return &"strong" if rng_.randf() < clampf(Balance.strong_probability + strong_prob_bonus, 0.0, 1.0) else &"weak"


func _pick_idle_duration(rng_: RandomNumberGenerator) -> int:
	return rng_.randi_range(Balance.idle_min_ticks, Balance.idle_max_ticks)


# Endless scaling: speed_scale > 1.0 zkracuje telegraphs/recovery, floors
# guarantee they never hit 0 ticks. At speed_scale 1.0 (default) the round()
# is a no-op and the floors never bind — pre-endless behaviour is identical.

func _threat_weak_ticks() -> int:
	return maxi(Balance.endless_threat_weak_floor, int(round(Balance.threat_weak_ticks / speed_scale)))


func _threat_strong_ticks() -> int:
	return maxi(Balance.endless_threat_strong_floor, int(round(Balance.threat_strong_ticks / speed_scale)))


func _recovery_weak_ticks() -> int:
	return maxi(Balance.endless_recovery_weak_floor, int(round(Balance.recovery_weak_ticks / speed_scale)))


func _recovery_strong_ticks() -> int:
	return maxi(Balance.endless_recovery_strong_floor, int(round(Balance.recovery_strong_ticks / speed_scale)))


func _exhausted_ticks() -> int:
	return Balance.exhausted_ticks


func _stagger_ticks() -> int:
	return Balance.stagger_ticks


func _feint_probability() -> float:
	return Balance.feint_probability


func _feint_idle_ticks() -> int:
	return Balance.feint_idle_ticks

